import{C as r,o as t,c as n,a5 as a,E as o}from"./chunks/framework.CW28V7p_.js";const c=JSON.parse('{"title":"2. Turbine — block propagation","description":"","frontmatter":{},"headers":[],"relativePath":"module-5/2-turbine.md","filePath":"module-5/2-turbine.md","lastUpdated":1780937944000}'),l={name:"module-5/2-turbine.md"},u=Object.assign(l,{setup(d){const s={id:"m5-2-turbine",title:"🧠 Mini-check: Turbine",intro:"3 питання — block propagation.",questions:[{type:"mcq",q:"Чому Turbine використовує tree structure а не broadcast (leader → всім напряму)?",options:["Bandwidth: leader не має enough для send блок до 2000+ validators одночасно","Latency: tree пропагація швидша ніж sequential broadcast","Resilience: hierarchical structure resilient до node failures","Security: tree prevents DoS attacks"],correct:[0,1,2],explanation:"Direct broadcast би overwhelm leader bandwidth. Tree distributes load. Module 5.2."},{type:"explain",q:"Поясни як turbine tree формується і чому позиція validator у tree affects performance.",ideal:`Turbine tree:
1. Leader = root
2. Children = subset validators (e.g., 200 first-layer neighbors)
3. Their children = next layer
4. Cascade until reach всі validators

Два-три levels typically для mainnet ~2000 validators.

Position matters:
- Layer 1 (close до leader): receive shreds first, ~0-20ms after leader produces. Low latency, more chances to vote on time.
- Layer 2: receive ~30-60ms after.
- Layer 3 (deep): receive ~100ms+ after. Higher chance to miss vote window.

Tree shuffled per slot (stake-weighted). Validators з більшим stake more likely в layer 1.

Resilience: erasure coding (Reed-Solomon) дозволяє recover block з ~50% shreds. Even якщо some tree branches fail.

For operator: low network latency до major datacenters (where most stake located) = better position у tree consistently.`,explanation:"Module 5.2."},{type:"mcq",q:"Якщо validator misses 30% shreds через packet loss — він може reconstruct block?",options:["Так, якщо ≤ 50% loss (erasure coding handles до 50%)","Ні, потрібен 100% delivery","Тільки через repair protocol","Залежить від turbine layer"],correct:[0],explanation:"Reed-Solomon erasure coding у turbine дозволяє reconstruct з ~50% shreds. Module 5.2, 5.3."}]};return(p,e)=>{const i=r("Quiz");return t(),n("div",null,[e[0]||(e[0]=a(`<h1 id="_2-turbine-—-block-propagation" tabindex="-1">2. Turbine — block propagation <a class="header-anchor" href="#_2-turbine-—-block-propagation" aria-label="Permalink to &quot;2. Turbine — block propagation&quot;">​</a></h1><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p><strong>Turbine</strong> — Solana&#39;s block propagation protocol. Leader <strong>не</strong> broadcasts block до всіх validators напряму. Замість того створюється hierarchical tree: leader sends shreds до small set neighbors (layer 1), they forward до layer 2, etc. Cascade reaches whole cluster fast без overloading leader bandwidth.</p><h2 id="концепти" tabindex="-1">Концепти <a class="header-anchor" href="#концепти" aria-label="Permalink to &quot;Концепти&quot;">​</a></h2><h3 id="чому-не-direct-broadcast" tabindex="-1">Чому не direct broadcast <a class="header-anchor" href="#чому-не-direct-broadcast" aria-label="Permalink to &quot;Чому не direct broadcast&quot;">​</a></h3><p>Mainnet ~2000 validators. Block ~10KB (~32 shreds × 1280 bytes). Якщо leader sends block до всіх:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bandwidth = 10KB × 2000 = 20MB per block</span></span>
<span class="line"><span>Per slot rate = 20MB / 0.4s = 50 MB/s = 400 Mbps from leader</span></span></code></pre></div><p>Most validators не мають 400 Mbps available для leadership. Direct broadcast не feasible.</p><p>Solution: <strong>tree multicast</strong> — leader sends до small subset, they forward.</p><h3 id="turbine-tree-structure" tabindex="-1">Turbine tree structure <a class="header-anchor" href="#turbine-tree-structure" aria-label="Permalink to &quot;Turbine tree structure&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Layer 0:         Leader</span></span>
<span class="line"><span>                   |</span></span>
<span class="line"><span>                   v</span></span>
<span class="line"><span>Layer 1:    [validators A, B, C, ..., X]   (~200 nodes)</span></span>
<span class="line"><span>              |        |        |</span></span>
<span class="line"><span>              v        v        v</span></span>
<span class="line"><span>Layer 2:    nodes    nodes    nodes        (next ~1800 nodes split across)</span></span></code></pre></div><p>Typical 2-3 layers для mainnet sized cluster.</p><p>Кожен layer receives shreds, forwards до next layer. Cascade ends коли всі validators received shreds.</p><h3 id="tree-generation-per-slot" tabindex="-1">Tree generation (per slot) <a class="header-anchor" href="#tree-generation-per-slot" aria-label="Permalink to &quot;Tree generation (per slot)&quot;">​</a></h3><p>Tree shuffled deterministically per slot, stake-weighted:</p><ul><li>Higher stake → more likely у early layers</li><li>Lower stake → more likely deeper</li></ul><p>Це incentive: more stake = better network position.</p><h3 id="erasure-coding-reed-solomon" tabindex="-1">Erasure coding (Reed-Solomon) <a class="header-anchor" href="#erasure-coding-reed-solomon" aria-label="Permalink to &quot;Erasure coding (Reed-Solomon)&quot;">​</a></h3><p>Турбіна uses <strong>Reed-Solomon</strong> erasure coding для resilience:</p><ul><li>Block split into 32 data shreds</li><li>Compute 32 parity shreds (redundancy)</li><li>64 total shreds broadcast</li></ul><p>Validator can reconstruct block з <strong>будь-якими 32+ shreds</strong> (з 64). I.e., може lose up to 50% shreds без losing block.</p><p>Це critical для UDP-based protocol (packet loss inevitable).</p><h3 id="performance-implications" tabindex="-1">Performance implications <a class="header-anchor" href="#performance-implications" aria-label="Permalink to &quot;Performance implications&quot;">​</a></h3><p>Validator&#39;s turbine position affects:</p><ul><li><strong>Latency receive shreds</strong>: layer 1 = first, layer 3 = last</li><li><strong>Vote timing</strong>: must vote ASAP після reconstruct block. Late position = late vote = potentially miss credit window</li><li><strong>Block forward bandwidth</strong>: layer 1 must forward many shreds to children</li></ul><p>Tier 1 validators (high stake, good network) consistently у layer 1 — getting best performance — earning most credits — staying high stake. Network effect.</p><h2 id="connect-to-your-work" tabindex="-1">Connect to your work <a class="header-anchor" href="#connect-to-your-work" aria-label="Permalink to &quot;Connect to your work&quot;">​</a></h2><h3 id="network-requirements" tabindex="-1">Network requirements <a class="header-anchor" href="#network-requirements" aria-label="Permalink to &quot;Network requirements&quot;">​</a></h3><p>Для good turbine performance:</p><ul><li><strong>Low latency</strong> до cluster centroid (where most stake located). Mainnet ~Equinix data centers.</li><li><strong>High bandwidth</strong>: 1Gbps+ symmetric. 10Gbps preferred.</li><li><strong>Low packet loss</strong>: enterprise ISP, dedicated lines preferred</li></ul><p>Якщо твій server у далекому location — perpetually layer 3 → higher skip rate → less credits.</p><h3 id="monitoring-turbine-performance" tabindex="-1">Monitoring turbine performance <a class="header-anchor" href="#monitoring-turbine-performance" aria-label="Permalink to &quot;Monitoring turbine performance&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> journalctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> solana</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -iE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;turbine|shred&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -20</span></span></code></pre></div><p>Look for:</p><ul><li>&quot;Turbine shred broadcast failed&quot; — network issue</li><li>&quot;Repair needed for slot X&quot; — missed shreds</li><li>&quot;Reconstructing block from N shreds&quot; — partial receive</li></ul><h2 id="hands-on-exercise" tabindex="-1">Hands-on exercise <a class="header-anchor" href="#hands-on-exercise" aria-label="Permalink to &quot;Hands-on exercise&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Поточні tcp/udp connections</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ss</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -tunap</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agave-validator</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -10</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Network bandwidth usage</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> iftop</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> eth0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> 2&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/dev/null</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ||</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> nethogs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> eth0</span></span></code></pre></div><h2 id="mini-quiz" tabindex="-1">Mini-quiz <a class="header-anchor" href="#mini-quiz" aria-label="Permalink to &quot;Mini-quiz&quot;">​</a></h2>`,38)),o(i,{data:s}),e[1]||(e[1]=a('<h2 id="glossary-additions" tabindex="-1">Glossary additions <a class="header-anchor" href="#glossary-additions" aria-label="Permalink to &quot;Glossary additions&quot;">​</a></h2><p><a href="/glossary#t"><code>Turbine</code></a>, <a href="/glossary#m"><code>Multicast</code></a>, <a href="/glossary#t"><code>Turbine tree</code></a>, <a href="/glossary#l"><code>Layer (turbine)</code></a>, <a href="/glossary#r"><code>Reed-Solomon</code></a></p><h2 id="external-refs" tabindex="-1">External refs <a class="header-anchor" href="#external-refs" aria-label="Permalink to &quot;External refs&quot;">​</a></h2><ul><li><a href="https://docs.anza.xyz/consensus/turbine-block-propagation" target="_blank" rel="noreferrer">Anza: Turbine</a></li></ul><hr><p><strong>Попередньо:</strong> <a href="/module-5/1-gossip">← 1. Gossip</a> | <strong>Наступне:</strong> <a href="/module-5/3-shreds">3. Shreds →</a></p>',6))])}}});export{c as __pageData,u as default};
